package app.org.apache.roller.weblogger.ui.tags;

public class TruncateNicelyTag extends StringTagSupport { private String lower ; private String upper ; private String appendToEnd ; public TruncateNicelyTag ( ) { super ( ) ; } public String getLower ( ) { return this . lower ; } public void setLower ( String lower ) { this . lower = lower ; } public String getUpper ( ) { return this . upper ; } public void setUpper ( String upper ) { this . upper = upper ; } public String getAppendToEnd ( ) { return this . appendToEnd ; } public void setAppendToEnd ( String s ) { this . appendToEnd = s ; } public String changeString ( String text ) throws JspException { int l = NumberUtils . toInt ( lower ) ; int u = NumberUtils . toInt ( upper ) ; return truncateNicely ( text , l , u , this . appendToEnd ) ; } public void initAttributes ( ) { this . lower = "10" ; this . upper = "-1" ; this . appendToEnd = "..." ; } private static String truncateNicely ( String str , int lower , int upper , String appendToEnd ) { str = removeXml ( str ) ; if ( upper < lower ) { upper = lower ; } if ( str . length ( ) > upper ) { int loc ; loc = str . lastIndexOf ( ' ' , upper ) ; if ( loc >= lower ) { str = str . substring ( 0 , loc ) ; } else { str = str . substring ( 0 , upper ) ; } str = str + appendToEnd ; } return str ; } private static String removeXml ( String str ) { int sz = str . length ( ) ; StringBuilder buffer = new StringBuilder ( sz ) ; boolean inTag = false ; for ( int i = 0 ; i < sz ; i ++ ) { char ch = str . charAt ( i ) ; if ( ch == '<' ) { inTag = true ; } else if ( ch == '>' ) { inTag = false ; continue ; } if ( ! inTag ) { buffer . append ( ch ) ; } } return buffer . toString ( ) ; } }